<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/.local/share/chezmoi/scripts/install-fonts.sh nerdfonts</span></span>
